var seed = GetInt(parameters, "seed", context.Seed);
var flameColor = GetColor(parameters, "flameColor", System.Windows.Media.Color.FromRgb(255, 140, 0));
var innerColor = GetColor(parameters, "innerColor", System.Windows.Media.Color.FromRgb(255, 238, 128));
var brightness = GetFloat(parameters, "brightness", 0.8f);
var sizeParam = GetFloat(parameters, "size", 1.0f);

var size = context.TileSize;
var half = size * 0.5f;
var maxH = size * sizeParam * 0.45f;
var maxW = size * sizeParam * 0.35f;
var seedVal = seed;

var result = new PixelBuffer(size, size);

var oR = flameColor.R / 255f;
var oG = flameColor.G / 255f;
var oB = flameColor.B / 255f;
var iR = innerColor.R / 255f;
var iG = innerColor.G / 255f;
var iB = innerColor.B / 255f;

result.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f - half) / maxW;
    var v = (y + 0.5f - (size - half)) / maxH; // flame sits above center

    // Flame base at v=-0.3, tip at v=1.2
    var localV = (v + 0.3f) / 1.5f; // 0=base, 1=tip

    if (localV < 0f || localV > 1f) { result.SetPixel(x, y, 0, 0, 0, 0); return; }

    // Teardrop flame profile: wider at base, narrow at tip
    var baseWidth = 1f - localV * 0.3f;
    var tipWidth = 1f - (1f - localV) * (1f - localV) * 0.7f;
    var flameWidth = baseWidth * tipWidth;

    // Core width (the bright inner part)
    var coreFrac = 0.3f + localV * 0.2f;
    var coreWidth = flameWidth * coreFrac;

    // Distance from flame centerline
    var dist = MathF.Abs(u) / Math.Max(0.01f, flameWidth);
    var coreDist = MathF.Abs(u) / Math.Max(0.01f, coreWidth);

    // Organic waviness on edges
    var waveX = MathF.Sin(localV * 10f + seedVal) * 0.08f +
                MathF.Sin(localV * 23f + seedVal * 3) * 0.04f;
    var wavyDist = MathF.Abs(u - waveX * (1f - localV)) / Math.Max(0.01f, flameWidth);

    // Turbulent flicker at the tip
    var tipFlicker = 1f - MathF.Pow(1f - localV, 0.5f) * 0.15f *
        MathF.Abs(MathF.Sin(localV * 40f + seedVal * 7));

    // Intensity profiles
    var outerIntensity = Math.Clamp(1f - wavyDist * 0.8f, 0f, 1f) * brightness * tipFlicker;
    var innerIntensity = Math.Clamp(1f - coreDist * 0.6f, 0f, 1f) * brightness * tipFlicker;

    // Spatial variation along flame for color mixing
    var t = localV;
    var r = Lerp(oR, iR, t * 0.5f) * outerIntensity + iR * innerIntensity * 0.3f;
    var g = Lerp(oG, iG, t * 0.5f) * outerIntensity * 0.8f + iG * innerIntensity * 0.3f;
    var b = Lerp(oB, iB, t * 0.3f) * outerIntensity * 0.4f + 0.1f * outerIntensity;

    var alpha = Math.Clamp(outerIntensity * 0.9f, 0f, 1f);

    result.SetPixel(x, y, Math.Clamp(r, 0, 1), Math.Clamp(g, 0, 1), Math.Clamp(b, 0, 1), alpha);

});

return result;
}
